test('allows an existing _menu_item_object_id metadata row to retarget to a post created by the same plan even when a navigation menu taxonomy is blocked elsewhere', () => {
  const resourceKey = 'row:["wp_postmeta","meta_id:461"]';
  const targetResourceKey = 'row:["wp_posts","ID:2"]';
  const blockedTaxonomyResourceKey = 'row:["wp_term_taxonomy","term_taxonomy_id:20"]';
  const base = baseSite();
  const local = baseSite();
  const remote = baseSite();
  base.db.wp_postmeta = {
    'meta_id:461': {
      meta_id: 461,
      post_id: 1,
      meta_key: '_menu_item_object_id',
      meta_value: 1,
    },
  };
  remote.db.wp_postmeta = {
    'meta_id:461': {
      ...base.db.wp_postmeta['meta_id:461'],
    },
  };
  local.db.wp_posts['ID:2'] = {
    ID: 2,
    post_title: 'Local menu object post',
    post_content: 'local-private-menu-object-body',
    post_status: 'publish',
  };
  local.db.wp_terms = {
    'term_id:8': {
      term_id: 8,
      name: 'Local blocked elsewhere nav menu term',
      slug: 'local-blocked-elsewhere-nav-menu-term',
    },
  };
  local.db.wp_term_taxonomy = {
    'term_taxonomy_id:20': {
      term_taxonomy_id: 20,
      term_id: 8,
      taxonomy: 'nav_menu',
      description: '',
      parent: 0,
      count: 0,
    },
  };
  local.db.wp_postmeta = {
    'meta_id:461': {
      meta_id: 461,
      post_id: 1,
      meta_key: '_menu_item_object_id',
      meta_value: 2,
    },
  };

  const plan = planFor(base, local, remote);
  const targetMutation = mutationFor(plan, targetResourceKey);
  const blockedTaxonomy = plan.blockers.find((entry) => entry.resourceKey === blockedTaxonomyResourceKey);
  const postmetaMutation = mutationFor(plan, resourceKey);
  const reference = postmetaMutation.wordpressGraphReferences.find((entry) => entry.relationshipType === 'menu-item-object-post');

  assert.equal(plan.status, 'blocked');
  assert.equal(blockedTaxonomy.surface, 'nav_menu');
  assert.equal(targetMutation.changeKind, 'create');
  assert.equal(mutationFor(plan, blockedTaxonomyResourceKey), undefined);
  assert.equal(postmetaMutation.changeKind, 'update');
  assert.ok(
    plan.mutations.indexOf(targetMutation) < plan.mutations.indexOf(postmetaMutation),
    'target post create must be ordered before dependent existing menu item object metadata',
  );
  assert.deepEqual(postmetaMutation.dependsOnMutationIds, [targetMutation.id]);
  assert.equal(plan.summary.graphDependencies, 1);
  assert.deepEqual(plan.graphDependencies, [
    {
      sourceMutationId: postmetaMutation.id,
      sourceResourceKey: resourceKey,
      relationshipKey: 'wp_postmeta.meta_value',
      relationshipType: 'menu-item-object-post',
      targetMutationId: targetMutation.id,
      targetResourceKey,
      resolutionPolicy: 'same-plan-local-create',
      source: 'same-plan-local-create',
      targetLocalHash: targetMutation.localHash,
    },
  ]);
  assert.equal(reference.resolutionPolicy, 'same-plan-local-create');
  assert.equal(reference.relationshipKey, 'wp_postmeta.meta_value');
  assert.equal(reference.relationshipType, 'menu-item-object-post');
  assert.equal(reference.targetResourceKey, targetResourceKey);
  assert.equal(JSON.stringify(reference).includes('Local blocked elsewhere nav menu term'), false);
  assert.equal(JSON.stringify(reference).includes('local-private-menu-object-body'), false);
});

